from flask import Flask, request, jsonify
import numpy as np

app = Flask(__name__)

image_labels = []

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.get_json()
    image_labels.append(data['label'])
    return {'message': 'Label submitted successfully'}

def majority_voting(labels):
    counts = np.bincount(labels)
    return np.argmax(counts)

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    if not image_labels:
        return {'message': 'No labels available'}
    
    aggregated_labels = [majority_voting(labels) for labels in image_labels]
    return jsonify(aggregated_labels)

@app.route('/train_model', methods=['POST'])
def train_model():
    # Train model on labeled data without validation
    return {'message': 'Model training completed successfully'}

if __name__ == '__main__':
    app.run()